{
"sql": "SELECT g.Name AS Genre, SUM(il.UnitPrice * il.Quantity) AS TotalSales FROM Genre g JOIN Track t ON g.GenreId = t.GenreId JOIN InvoiceLine il ON t.TrackId = il.TrackId GROUP BY g.GenreId, g.Name ORDER BY TotalSales DESC LIMIT 5",
"rationale": "Aggregate sales by genre, sum the product of unit price and quantity, order descending, and limit to top 5."
}

{
"sql": "SELECT Album.Title FROM Album INNER JOIN Artist ON Album.ArtistId = Artist.ArtistId WHERE Artist.Name = 'AC/DC'",
"rationale": "Join Album and Artist tables to filter albums by the artist name 'AC/DC' and return their titles."
}

{
"sql": "SELECT FirstName, LastName, Email FROM Customer WHERE Country = 'Brazil'",
"rationale": "Retrieve first name, last name, and email for customers located in Brazil."
}

{
"sql": "SELECT m.Name FROM MediaType m JOIN Track t ON m.MediaTypeId = t.MediaTypeId GROUP BY m.MediaTypeId ORDER BY COUNT(*) DESC LIMIT 1",
"rationale": "Count tracks per media type and return the one with the highest count."
}

{
"sql": "SELECT e.FirstName || ' ' || e.LastName AS EmployeeName FROM Customer c JOIN Employee e ON c.SupportRepId = e.EmployeeId GROUP BY e.EmployeeId ORDER BY COUNT(*) DESC LIMIT 1",
"rationale": "Count customers per support rep, order descending, and limit to 1 to get the employee with the most assigned customers."
}

{
"sql": "SELECT Playlist.Name, COUNT(Track.TrackId) AS TrackCount FROM Playlist LEFT JOIN PlaylistTrack ON Playlist.PlaylistId = PlaylistTrack.PlaylistId LEFT JOIN Track ON PlaylistTrack.TrackId = Track.TrackId GROUP BY Playlist.PlaylistId, Playlist.Name",
"rationale": "Count the number of tracks in each playlist by joining Playlist, PlaylistTrack, and Track, grouping by playlist."
}

{
"sql": "SELECT SUM(il.UnitPrice * il.Quantity) AS total_revenue FROM InvoiceLine il JOIN Invoice i ON il.InvoiceId = i.InvoiceId WHERE strftime('%Y', i.InvoiceDate) = '2021'",
"rationale": "Sum the product of UnitPrice and Quantity from InvoiceLine for invoices dated in 2021."
}

{
"sql": "SELECT BillingCountry, AVG(Total) AS AverageTotal FROM Invoice GROUP BY BillingCountry ORDER BY AverageTotal DESC",
"rationale": "Calculate average invoice total per billing country and sort descending."
}

{
"sql": "SELECT a.Name, COUNT(DISTINCT t.GenreId) AS genre_count FROM Artist a JOIN Album al ON a.ArtistId = al.ArtistId JOIN Track t ON al.AlbumId = t.AlbumId GROUP BY a.ArtistId, a.Name HAVING COUNT(DISTINCT t.GenreId) > 3",
"rationale": "Join Artist, Album, and Track to count distinct genres per artist, then filter those with more than 3."
}

{
"sql": "SELECT COUNT(*) FROM Track WHERE Milliseconds > (SELECT AVG(Milliseconds) FROM Track)",
"rationale": "Count tracks whose length in milliseconds exceeds the average track length."
}

{
"sql": "SELECT CASE WHEN Milliseconds < 180000 THEN 'short' WHEN Milliseconds <= 300000 THEN 'medium' ELSE 'long' END AS bucket, COUNT(*) AS count FROM Track GROUP BY bucket ORDER BY CASE bucket WHEN 'short' THEN 1 WHEN 'medium' THEN 2 WHEN 'long' THEN 3 END",
"rationale": "Categorize each track into short, medium, or long based on milliseconds and count the number of tracks in each bucket."
}

{
"sql": "SELECT FirstName || ' ' || LastName AS FullName, Title FROM Employee WHERE ReportsTo IS NULL",
"rationale": "Retrieve employees with no manager (ReportsTo IS NULL) and display their full name and title."
}

{
"sql": "SELECT COUNT(*) FROM Invoice WHERE InvoiceDate >= '2022-01-01' AND InvoiceDate < '2022-04-01'",
"rationale": "Counts all invoices with InvoiceDate in the first quarter of 2022."
}

{
"sql": "SELECT e.FirstName || ' ' || e.LastName AS EmployeeName, m.FirstName || ' ' || m.LastName AS ManagerName FROM Employee e LEFT JOIN Employee m ON e.ReportsTo = m.EmployeeId",
"rationale": "Self-join Employee on ReportsTo to get manager's name, using LEFT JOIN to include employees with no manager."
}

{
"sql": "SELECT COUNT(DISTINCT Country) FROM Customer",
"rationale": "Count the number of distinct countries present in the Customer table."
}

{
"sql": "SELECT Country FROM Customer UNION SELECT BillingCountry FROM Invoice ORDER BY Country",
"rationale": "Combine distinct countries from Customer and Invoice tables, remove duplicates, and sort alphabetically."
}

{
"sql": "SELECT AVG(track_count) AS avg_tracks_per_album FROM (SELECT COUNT(T.TrackId) AS track_count FROM Album A LEFT JOIN Track T ON A.AlbumId = T.AlbumId GROUP BY A.AlbumId)",
"rationale": "Compute the average number of tracks per album by counting tracks for each album (including those with zero) and then averaging."
}

{
"sql": "SELECT e.FirstName || ' ' || e.LastName AS EmployeeName, COUNT(c.CustomerId) AS CustomerCount FROM Employee e LEFT JOIN Customer c ON e.EmployeeId = c.SupportRepId GROUP BY e.EmployeeId, e.FirstName, e.LastName ORDER BY CustomerCount DESC, EmployeeName",
"rationale": "Left join Employee to Customer on SupportRepId, group by employee, count customers, order by count descending then employee name."
}

{
"sql": "SELECT COUNT(*) FROM Track WHERE LOWER(Name) LIKE '%love%'",
"rationale": "Counts tracks whose name contains the substring 'love' case-insensitively."
}

{
"sql": "SELECT CASE WHEN Total < 5 THEN 'small' WHEN Total <= 10 THEN 'medium' ELSE 'large' END AS bucket, COUNT(*) AS count FROM Invoice GROUP BY bucket ORDER BY CASE bucket WHEN 'small' THEN 1 WHEN 'medium' THEN 2 WHEN 'large' THEN 3 END",
"rationale": "Group invoices by total into three buckets using a CASE expression and count the number of invoices in each bucket."
}

{
"sql": "SELECT SUM(Total) AS total_revenue FROM Invoice WHERE InvoiceDate >= date((SELECT MAX(InvoiceDate) FROM Invoice), '-6 months')",
"rationale": "Sum the Total column for invoices dated within the last 6 months of the maximum invoice date."
}

{
"sql": "SELECT c.FirstName || ' ' || c.LastName AS Name, c.City, COUNT(i.InvoiceId) AS InvoiceCount FROM Customer c JOIN Invoice i ON c.CustomerId = i.CustomerId WHERE c.City LIKE 'S%' GROUP BY c.CustomerId HAVING COUNT(i.InvoiceId) > 1 ORDER BY InvoiceCount DESC, Name",
"rationale": "Count invoices per customer, filter by city starting with 'S' and having more than one invoice, then order by count descending and name."
}

{
"sql": "SELECT Genre.Name AS Genre, SUM(InvoiceLine.UnitPrice * InvoiceLine.Quantity) AS TotalSales FROM InvoiceLine JOIN Track ON InvoiceLine.TrackId = Track.TrackId JOIN Genre ON Track.GenreId = Genre.GenreId GROUP BY Genre.Name ORDER BY TotalSales DESC LIMIT 5",
"rationale": "Calculates total sales per genre by summing UnitPrice * Quantity from InvoiceLine, joins through Track to Genre, groups by genre name, and returns the top 5."
}

{
"sql": "SELECT Album.Title FROM Album JOIN Artist ON Album.ArtistId = Artist.ArtistId WHERE Artist.Name = 'AC/DC'",
"rationale": "Join Album with Artist on ArtistId and filter where the artist name is 'AC/DC' to return the album titles."
}

{
"sql": "SELECT FirstName, LastName, Email FROM Customer WHERE Country = 'Brazil'",
