}

{
"sql": "SELECT MediaType.Name FROM MediaType JOIN Track ON MediaType.MediaTypeId = Track.MediaTypeId GROUP BY MediaType.Name ORDER BY COUNT(Track.TrackId) DESC LIMIT 1",
"rationale": "Finds the media type with the highest number of tracks by joining the Track and MediaType tables, grouping by media type, and ordering by the track count in descending order."
}

{
"sql": "SELECT FirstName || ' ' || LastName AS EmployeeName FROM Employee WHERE EmployeeId = (SELECT SupportRepId FROM Customer GROUP BY SupportRepId ORDER BY COUNT(*) DESC LIMIT 1)",
"rationale": "Finds the employee with the most customers by counting Customer records per SupportRepId and returning the matching employee's full name."
}

{
"sql": "SELECT SUM(InvoiceLine.UnitPrice * InvoiceLine.Quantity) AS TotalRevenue FROM InvoiceLine JOIN Invoice ON InvoiceLine.InvoiceId = Invoice.InvoiceId WHERE strftime('%Y', Invoice.InvoiceDate) = '2021'",
"rationale": "Calculates total revenue by summing UnitPrice * Quantity for invoice lines where the invoice date falls in 2021."
}

{
"sql": "SELECT BillingCountry, AVG(Total) AS AverageTotal FROM Invoice GROUP BY BillingCountry ORDER BY AverageTotal DESC",
"rationale": "Groups invoices by billing country, computes the average Total per country, and sorts the results from highest to lowest average."
}

