{
"sql": "SELECT Artist.Name, COUNT(DISTINCT Track.GenreId) AS GenreCount FROM Artist JOIN Album ON Artist.ArtistId = Album.ArtistId JOIN Track ON Album.AlbumId = Track.AlbumId GROUP BY Artist.ArtistId HAVING COUNT(DISTINCT Track.GenreId) > 3",
"rationale": "Join Artist→Album→Track, count distinct GenreId per artist, and filter for those with more than 3 genres."
}

{
"sql": "SELECT COUNT(*) FROM Track WHERE Milliseconds > (SELECT AVG(Milliseconds) FROM Track)",
"rationale": "Count tracks whose Milliseconds exceed the overall average Milliseconds using a subquery."
}

{
"sql": "SELECT CASE WHEN Milliseconds < 180000 THEN 'short' WHEN Milliseconds BETWEEN 180000 AND 300000 THEN 'medium' ELSE 'long' END AS length_bucket, COUNT(*) AS track_count FROM Track GROUP BY length_bucket ORDER BY length_bucket",
"rationale": "Buckets tracks by converting Milliseconds to minutes via thresholds (3 min = 180000 ms, 5 min = 300000 ms) and counts tracks per bucket."
}

{
"sql": "SELECT FirstName || ' ' || LastName AS FullName, Title FROM Employee WHERE ReportsTo IS NULL",
"rationale": "Filters employees whose ReportsTo column is NULL (meaning they have no manager) and returns their concatenated full name and title."
}

{
"sql": "SELECT COUNT(InvoiceId) FROM Invoice WHERE InvoiceDate >= '2022-01-01' AND InvoiceDate < '2022-04-01'",
"rationale": "Counts the invoices where the invoice date falls within the first quarter of 2022."
}

{
"sql": "SELECT e.FirstName || ' ' || e.LastName AS EmployeeName, m.FirstName || ' ' || m.LastName AS ManagerName FROM Employee e LEFT JOIN Employee m ON e.ReportsTo = m.EmployeeId",
"rationale": "Self-join Employee to itself using a LEFT JOIN on ReportsTo so employees without a manager still appear with a NULL manager name."
}

{
"sql": "SELECT Country FROM Customer UNION SELECT BillingCountry AS Country FROM Invoice ORDER BY Country",
"rationale": "Combines distinct countries from Customer and BillingCountry from Invoice using UNION, then sorts alphabetically."
}

{
"sql": "SELECT AVG(c) FROM (SELECT COUNT(*) AS c FROM Track GROUP BY AlbumId)",
"rationale": "Calculates the average count of tracks by first counting tracks per album, then averaging those counts."
}

{
"sql": "SELECT FirstName || ' ' || LastName AS EmployeeName, COUNT(Customer.CustomerId) AS CustomerCount FROM Employee LEFT JOIN Customer ON Employee.EmployeeId = Customer.SupportRepId GROUP BY Employee.EmployeeId ORDER BY CustomerCount DESC, EmployeeName",
"rationale": "Left join Employee to Customer on SupportRepId, count customers per employee (0 for nulls via COUNT), and order by the count descending then the concatenated employee name."
}

{
"sql": "SELECT COUNT(*) FROM Track WHERE Name LIKE '%love%'",
"rationale": "Counts tracks whose name contains 'love' anywhere, using SQLite's case-insensitive LIKE operator."
}

{
"sql": "SELECT g.Name AS GenreName, t.Name AS TrackName, t.Milliseconds FROM Track t JOIN Genre g ON t.GenreId = g.GenreId WHERE t.Milliseconds = (SELECT MAX(t2.Milliseconds) FROM Track t2 WHERE t2.GenreId = t.GenreId) ORDER BY g.Name",
"rationale": "Finds the track with the maximum Milliseconds per genre using a correlated subquery, joins to Genre for the genre name, and orders by genre name."
}

{
"sql": "SELECT CASE WHEN Total < 5 THEN 'small' WHEN Total >= 5 AND Total <= 10 THEN 'medium' ELSE 'large' END AS bucket, COUNT(*) AS invoice_count FROM Invoice GROUP BY bucket ORDER BY bucket",
"rationale": "Uses a CASE expression to classify each invoice's Total into small/medium/large buckets, then counts invoices per bucket."
}

{
"sql": "SELECT SUM(UnitPrice * Quantity) FROM InvoiceLine JOIN Invoice ON InvoiceLine.InvoiceId = Invoice.InvoiceId WHERE Invoice.InvoiceDate >= (SELECT date(MAX(InvoiceDate), '-6 months') FROM Invoice)",
"rationale": "Calculates total revenue by summing UnitPrice * Quantity from InvoiceLine for invoices within the last 6 months of the most recent invoice date."
}

{
"sql": "SELECT FirstName || ' ' || LastName AS Name, City, COUNT(Invoice.InvoiceId) AS InvoiceCount FROM Customer JOIN Invoice ON Customer.CustomerId = Invoice.CustomerId WHERE City LIKE 'S%' GROUP BY Customer.CustomerId HAVING COUNT(Invoice.InvoiceId) > 1 ORDER BY InvoiceCount DESC, Name",
"rationale": "Join Customer with Invoice, filter cities starting with 'S', group by customer, keep those with more than 1 invoice, and order by count descending then name."
}

{
"sql": "SELECT FirstName || ' ' || LastName AS Name, Email FROM Customer WHERE Country = 'Brazil'",
"rationale": "Filter customers by Brazil and return their full names (concatenated) and email addresses."
}

{
"sql": "SELECT e.FirstName || ' ' || e.LastName AS EmployeeName FROM Employee e JOIN Customer c ON e.EmployeeId = c.SupportRepId GROUP BY e.EmployeeId, e.FirstName, e.LastName ORDER BY COUNT(*) DESC LIMIT 1",
"rationale": "Joins Employee with Customer on SupportRepId, groups by employee, counts customers per employee, and returns the top one sorted by count descending."
}

{
"sql": "SELECT Playlist.Name, COUNT(PlaylistTrack.TrackId) AS TrackCount FROM Playlist LEFT JOIN PlaylistTrack ON Playlist.PlaylistId = PlaylistTrack.PlaylistId GROUP BY Playlist.PlaylistId, Playlist.Name",
"rationale": "Counts tracks per playlist by joining Playlist with PlaylistTrack and grouping by playlist."
}

{
"sql": "SELECT FirstName || ' ' || LastName AS 'Full Name', Title FROM Employee WHERE ReportsTo IS NULL",
"rationale": "Filters for employees with a NULL ReportsTo value, indicating they have no manager, and returns their names and titles."
}

{
"sql": "SELECT g.Name, t.Name, t.Milliseconds FROM Track t JOIN Genre g ON t.GenreId = g.GenreId WHERE t.Milliseconds = (SELECT MAX(t2.Milliseconds) FROM Track t2 WHERE t2.GenreId = t.GenreId) ORDER BY g.Name",
"rationale": "Select the longest track per genre by matching each track to the maximumMilliseconds within its genre, then order the results alphabetically by genre name."
